// Extract body and validate fields
const input = $input.first().json;
const data = input.body || input;

const required = ['incidentId', 'severity', 'title', 'createdAt'];
for (const field of required) {
  if (!data[field]) {
    throw new Error(`Missing required field: ${field}`);
  }
}

// Map severity to number (P1=1, P2=2, etc)
const severityMap = { P1: 1, P2: 2, P3: 3, P4: 4 };
const sev = data.severity.toUpperCase();
if (!severityMap[sev]) {
  throw new Error(`Invalid severity value: ${data.severity}`);
}
const severityCode = severityMap[sev];

// Generate a unique key for deduplication
// Using a simple hash to keep it lightweight
function getHash(str) {
  let h = 5381;
  for (let i = 0; i < str.length; i++) {
    h = (h * 33) ^ str.charCodeAt(i);
  }
  return (h >>> 0).toString(16);
}
const keyBase = `${data.incidentId}:${sev}:${data.createdAt}`;
const dedupeKey = `${data.incidentId}-${getHash(keyBase)}`;

// Clean up description and messages
const desc = (data.description || '').trim();
const cleanDesc = desc.length > 240 ? desc.substring(0, 237) + '...' : desc;

return [{
  json: {
    ...data,
    severity: sev,
    severityRank: severityCode,
    description: cleanDesc,
    dedupeKey,
    // Prepared messages
    slackMsg: `[${sev} - Rank ${severityCode}] *${data.title}* (${data.incidentId})\n${cleanDesc ? cleanDesc + '\n' : ''}Store: ${data.storeId || 'N/A'}`,
    emailSub: `[${sev}] Incident: ${data.title} (${data.incidentId})`,
    emailBody: `Incident ID: ${data.incidentId}\nSeverity: ${sev} (${severityCode})\nTitle: ${data.title}\nCreated: ${data.createdAt}\n\nDescription:\n${cleanDesc || 'No description provided.'}`
  }
}];

const fs = require('fs');
const path = require('path');

const item = $input.first().json;
const key = item.dedupeKey;

// Persistent store file
const filePath = path.join(process.cwd(), 'processed_incidents.json');

let cache = [];
if (fs.existsSync(filePath)) {
  try {
    cache = JSON.parse(fs.readFileSync(filePath, 'utf8'));
  } catch (e) { cache = []; }
}

if (cache.includes(key)) {
  return [[], [{ json: { duplicate: true, key, id: item.incidentId } }]];
}

// Save and continue
cache.push(key);
if (cache.length > 1000) cache.shift(); // Keep it around 1k entries
fs.writeFileSync(filePath, JSON.stringify(cache), 'utf8');

return [[{ json: item }], []];

